CREATE VIEW `ads_sr_user_subscription_view` (`product_id` COMMENT "项目id", `user_id` COMMENT "用户id", `shop_item_type` COMMENT "项目类型", `create_time` COMMENT "订阅时间", `vip_expire_time` COMMENT "订阅过期时间") AS SELECT `dwd`.`dwd_trade_user_payorder`.`ProductId` AS `product_id`, `dwd`.`dwd_trade_user_payorder`.`UserId` AS `user_id`, CASE WHEN (`dwd`.`dwd_trade_user_payorder`.`ShopItem` IN (850)) THEN 'VIP' WHEN (`dwd`.`dwd_trade_user_payorder`.`ShopItem` IN (810)) THEN 'SVIP' WHEN (`dwd`.`dwd_trade_user_payorder`.`ShopItem` IN (830, 840, 800)) THEN '签到卡' END AS `shop_item_type`, `dwd`.`dwd_trade_user_payorder`.`CreateTime` AS `create_time`, `dwd`.`dwd_trade_user_payorder`.`VipExpireTime` AS `vip_expire_time`
FROM `dwd`.`dwd_trade_user_payorder`
WHERE `dwd`.`dwd_trade_user_payorder`.`ShopItem` IN (810, 830, 840, 850, 800);